create table if not exists public.part_categories (
  id uuid primary key,
  parent_id uuid references public.part_categories(id),
  name text not null,
  slug text not null unique,
  risk_level text not null default 'green' check (risk_level in ('green','yellow','red','blocked')),
  is_active boolean not null default true,
  sort_order integer not null default 0,
  policy jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.wilayas (
  id integer primary key,
  name text not null,
  arabic_name text not null
);
create index if not exists idx_wilayas_name on public.wilayas(name);

create table if not exists public.communes (
  id text primary key,
  wilaya_id integer not null references public.wilayas(id),
  name text not null,
  arabic_name text not null
);
create index if not exists idx_communes_wilaya on public.communes(wilaya_id);
create index if not exists idx_communes_name on public.communes(name);

create table if not exists public.car_makes (
  id serial primary key,
  name text not null unique
);

create table if not exists public.car_models (
  id serial primary key,
  make_id integer not null references public.car_makes(id),
  base_model text not null,
  model_variant text,
  year integer not null,
  cylinders integer,
  engine_displacement numeric(6,2),
  unique(make_id, model_variant, year)
);
create index if not exists idx_car_models_make on public.car_models(make_id);
create index if not exists idx_car_models_base on public.car_models(make_id, base_model);
create index if not exists idx_car_models_year on public.car_models(year);

alter table public.wilayas enable row level security;
drop policy if exists "wilayas_public_read" on public.wilayas;
create policy "wilayas_public_read"
on public.wilayas
for select
to anon, authenticated
using (true);

alter table public.communes enable row level security;
drop policy if exists "communes_public_read" on public.communes;
create policy "communes_public_read"
on public.communes
for select
to anon, authenticated
using (true);

alter table public.car_makes enable row level security;
drop policy if exists "car_makes_public_read" on public.car_makes;
create policy "car_makes_public_read"
on public.car_makes
for select
to anon, authenticated
using (true);

alter table public.car_models enable row level security;
drop policy if exists "car_models_public_read" on public.car_models;
create policy "car_models_public_read"
on public.car_models
for select
to anon, authenticated
using (true);

alter table public.part_categories enable row level security;
drop policy if exists "part_categories_public_read" on public.part_categories;
create policy "part_categories_public_read"
on public.part_categories
for select
to anon, authenticated
using (true);

grant usage on schema public to anon, authenticated;
grant select on public.part_categories to anon, authenticated;
grant select on public.wilayas to anon, authenticated;
grant select on public.communes to anon, authenticated;
grant select on public.car_makes to anon, authenticated;
grant select on public.car_models to anon, authenticated;

on conflict (id) do update set
  name = excluded.name,
  slug = excluded.slug,
  risk_level = excluded.risk_level,
  is_active = excluded.is_active,
  sort_order = excluded.sort_order,
  policy = excluded.policy,
  updated_at = now();

on conflict (id) do update set name = excluded.name, arabic_name = excluded.arabic_name;

on conflict (id) do update set wilaya_id = excluded.wilaya_id, name = excluded.name, arabic_name = excluded.arabic_name;

on conflict (name) do nothing;

create temporary table if not exists _car_model_seed (
  make_name text not null,
  base_model text not null,
  model_variant text,
  year integer not null,
  cylinders integer,
  engine_displacement numeric(6,2)
) on commit drop;
truncate table _car_model_seed;
;

select
  deduped.make_id,
  deduped.base_model,
  deduped.model_variant,
  deduped.year,
  deduped.cylinders,
  deduped.engine_displacement
from (
  select
    m.id as make_id,
    s.base_model,
    s.model_variant,
    s.year,
    s.cylinders,
    s.engine_displacement,
    row_number() over (
      partition by m.id, s.model_variant, s.year
      order by s.base_model
    ) as row_rank
  from _car_model_seed s
  join public.car_makes m on m.name = s.make_name
) deduped
where deduped.row_rank = 1
on conflict (make_id, model_variant, year) do update set
  base_model = excluded.base_model,
  cylinders = excluded.cylinders,
  engine_displacement = excluded.engine_displacement;

